import React from "react";
import { Button } from "@/components/ui/button";

const data = [
  {
    "size": "sm",
    "text": "Small"
  },
  {
    "size": "default",
    "text": "Default"
  },
  {
    "size": "lg",
    "text": "Large"
  }
] as const;

export default function ButtonSizesExample() {
  return (
    <div className="flex flex-wrap items-center gap-3">
      {data.map((item, index) => (
        <Button key={index} size={item.size}>{item.text}</Button>
      ))}
    </div>
  );
}
